 27→    const [editorMode, setEditorMode] = useState(initialMode === 'canvas' ? 'canvas' : 'text');
 28→    const [title, setTitle] = useState(initialTitle || '')
 29→    const [wordCount, setWordCount] = useState(0);
 30→    const [editor] = useLexicalComposerContext();
 31→
 32→
 33→    const [uploadedImagePaths, setUploadedImagePaths] = useState([]);
 34→
 35→    const addUploadedImagePath = useCallback((imagePath) =>{
 36→      setUploadedImagePaths((prev) => [...prev, imagePath]);
 37→    }, [])
 38→
 39→    useEffect(() => {
 40→        setEditorMode(initialMode === 'canvas' ? 'canvas' : 'text');
 41→        setTitle(initialTitle || '');
 42→    }, [initialMode, initialTitle]);
 43→
 44→    const handleCloseEditor = useCallback(async() => {
 45→      if(uploadedImagePaths.length > 0){
